// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra;

import static org.junit.jupiter.api.Assertions.assertNotEquals;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.junit.jupiter.api.Test;

class ArbitraryLengthPathTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI SUBJECT = VF.createIRI("urn:test:subject");
	private static final IRI PREDICATE = VF.createIRI("urn:test:predicate");

	@Test
	void minimumLengthParticipatesInEqualityAndHashCode() {
		ArbitraryLengthPath zeroOrMore = fixedSelfPath(0);
		ArbitraryLengthPath oneOrMore = fixedSelfPath(1);

		assertNotEquals(zeroOrMore, oneOrMore);
		assertNotEquals(zeroOrMore.hashCode(), oneOrMore.hashCode());
	}

	private static ArbitraryLengthPath fixedSelfPath(long minLength) {
		Var start = Var.of("path-start", SUBJECT);
		Var end = Var.of("path-end", SUBJECT);
		StatementPattern step = new StatementPattern(
				start.clone(),
				Var.of("path-predicate", PREDICATE),
				end.clone());
		return new ArbitraryLengthPath(start, step, end, minLength);
	}
}
